'use client'

// IndiaMapClient.tsx
// Interactive India map for CAG Portal.
// SVG paths use IDs injsmap_1..36 (states 1-28, UTs 29-36).
// Each region maps to an ISO 3166-2 IN-XX code = map_region_id in states.json.
// Props:
//   jurisdiction — 'UT' | 'STATE' | 'LG' — which regions to highlight
//   reportCounts — Record<stateId, count> e.g. { 'IN-DL': 3, 'IN-JK': 1 }
//   onRegionClick(stateId) — called when a clickable region is clicked

import React, { useState } from 'react'
import { useRouter } from 'next/navigation'

// ── Complete ID → ISO code lookup ─────────────────────────────
const ID_TO_ISO: Record<string, string> = {
  injsmap_1:  'IN-AP', injsmap_2:  'IN-AR', injsmap_3:  'IN-AS',
  injsmap_4:  'IN-BR', injsmap_5:  'IN-CT', injsmap_6:  'IN-GA',
  injsmap_7:  'IN-GJ', injsmap_8:  'IN-HR', injsmap_9:  'IN-HP',
  injsmap_10: 'IN-JH', injsmap_11: 'IN-KA', injsmap_12: 'IN-KL',
  injsmap_13: 'IN-MP', injsmap_14: 'IN-MH', injsmap_15: 'IN-MN',
  injsmap_16: 'IN-ML', injsmap_17: 'IN-MZ', injsmap_18: 'IN-NL',
  injsmap_19: 'IN-OD', injsmap_20: 'IN-PB', injsmap_21: 'IN-RJ',
  injsmap_22: 'IN-SK', injsmap_23: 'IN-TN', injsmap_24: 'IN-TG',
  injsmap_25: 'IN-TR', injsmap_26: 'IN-UP', injsmap_27: 'IN-UK',
  injsmap_28: 'IN-WB',
  // UTs
  injsmap_29: 'IN-AN', injsmap_30: 'IN-CH', injsmap_31: 'IN-DD',
  injsmap_32: 'IN-DL', injsmap_33: 'IN-JK', injsmap_34: 'IN-LA',
  injsmap_35: 'IN-LD', injsmap_36: 'IN-PY',
}

// State IDs that are UTs
const UT_IDS = new Set([
  'IN-AN','IN-CH','IN-DD','IN-DL','IN-JK','IN-LA','IN-LD','IN-PY'
])
// State IDs that are states
const STATE_IDS = new Set([
  'IN-AP','IN-AR','IN-AS','IN-BR','IN-CT','IN-GA','IN-GJ','IN-HR',
  'IN-HP','IN-JH','IN-KA','IN-KL','IN-MP','IN-MH','IN-MN','IN-ML',
  'IN-MZ','IN-NL','IN-OD','IN-PB','IN-RJ','IN-SK','IN-TN','IN-TG',
  'IN-TR','IN-UP','IN-UK','IN-WB'
])

function isInJurisdiction(isoId: string, jurisdiction: string): boolean {
  if (jurisdiction === 'UT')    return UT_IDS.has(isoId)
  if (jurisdiction === 'STATE') return STATE_IDS.has(isoId)
  return true  // LG or ALL — show all
}

interface Props {
  jurisdiction: 'UT' | 'STATE' | 'LG' | 'UNION'
  reportCounts: Record<string, number>  // stateId → count (ignored for UNION)
  totalUnionReports?: number            // shown in tooltip for UNION map
  section?: string
}

export default function IndiaMapClient({ jurisdiction, reportCounts, totalUnionReports = 0, section = 'audit_reports' }: Props) {
  const router = useRouter()
  const [hoveredId, setHoveredId] = useState<string | null>(null)
  const [hoveredName, setHoveredName] = useState<string | null>(null)
  const [hoveredCount, setHoveredCount] = useState<number>(0)
  const [indiaHovered, setIndiaHovered] = useState(false)
  const [tooltip, setTooltip] = useState<{ x: number; y: number } | null>(null)

  const isUnion = jurisdiction === 'UNION'

  const handleClick = (svgId: string) => {
    if (isUnion) {
      router.push('/audit-reports?jurisdiction=UNION')
      return
    }
    const isoId = ID_TO_ISO[svgId]
    if (!isoId || !isInJurisdiction(isoId, jurisdiction)) return
    router.push(`/audit-reports?jurisdiction=${jurisdiction}&state=${isoId}`)
  }

  const handleMouseEnter = (svgId: string, name: string, e: React.MouseEvent) => {
    if (isUnion) {
      setIndiaHovered(true)
      const rect = (e.currentTarget as SVGElement).closest('svg')?.getBoundingClientRect()
      if (rect) setTooltip({ x: e.clientX - rect.left, y: e.clientY - rect.top })
      return
    }
    const isoId = ID_TO_ISO[svgId]
    if (!isoId || !isInJurisdiction(isoId, jurisdiction)) return
    setHoveredId(svgId)
    setHoveredName(name)
    setHoveredCount(reportCounts[isoId] || 0)
    const rect = (e.currentTarget as SVGElement).closest('svg')?.getBoundingClientRect()
    if (rect) setTooltip({ x: e.clientX - rect.left, y: e.clientY - rect.top })
  }

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!hoveredId && !indiaHovered) return
    const rect = (e.currentTarget as SVGElement).closest('svg')?.getBoundingClientRect()
    if (rect) setTooltip({ x: e.clientX - rect.left, y: e.clientY - rect.top })
  }

  const handleMouseLeave = () => {
    setHoveredId(null)
    setHoveredName(null)
    setIndiaHovered(false)
    setTooltip(null)
  }

  const getFill = (svgId: string): string => {
    if (isUnion) {
      return indiaHovered ? '#005999' : '#1a3a6b'  // whole India one colour
    }
    const isoId = ID_TO_ISO[svgId]
    if (!isoId) return '#EBECED'
    const inJur = isInJurisdiction(isoId, jurisdiction)
    if (!inJur) return '#E8E8E8'
    if (svgId === hoveredId) return '#005999'
    const count = reportCounts[isoId] || 0
    if (count > 0) return '#1a3a6b'
    return '#b8d4e8'
  }

  const getCursor = (svgId: string): string => {
    if (isUnion) return 'pointer'
    const isoId = ID_TO_ISO[svgId]
    if (!isoId || !isInJurisdiction(isoId, jurisdiction)) return 'default'
    return 'pointer'
  }

  // State names for tooltips (hover label)
  const NAMES: Record<string, string> = {
    injsmap_1:'Andhra Pradesh', injsmap_2:'Arunachal Pradesh', injsmap_3:'Assam',
    injsmap_4:'Bihar', injsmap_5:'Chhattisgarh', injsmap_6:'Goa',
    injsmap_7:'Gujarat', injsmap_8:'Haryana', injsmap_9:'Himachal Pradesh',
    injsmap_10:'Jharkhand', injsmap_11:'Karnataka', injsmap_12:'Kerala',
    injsmap_13:'Madhya Pradesh', injsmap_14:'Maharashtra', injsmap_15:'Manipur',
    injsmap_16:'Meghalaya', injsmap_17:'Mizoram', injsmap_18:'Nagaland',
    injsmap_19:'Odisha', injsmap_20:'Punjab', injsmap_21:'Rajasthan',
    injsmap_22:'Sikkim', injsmap_23:'Tamil Nadu', injsmap_24:'Telangana',
    injsmap_25:'Tripura', injsmap_26:'Uttar Pradesh', injsmap_27:'Uttarakhand',
    injsmap_28:'West Bengal', injsmap_29:'Andaman & Nicobar Islands',
    injsmap_30:'Chandigarh', injsmap_31:'Dadra, Nagar Haveli & Daman-Diu',
    injsmap_32:'Delhi', injsmap_33:'Jammu & Kashmir', injsmap_34:'Ladakh',
    injsmap_35:'Lakshadweep', injsmap_36:'Puducherry',
  }

  return (
    <div style={{ position: 'relative', width: '100%', maxWidth: '700px', margin: '0 auto' }}>
      {/* Legend */}
      {!isUnion && (
        <div style={{ display: 'flex', gap: '16px', flexWrap: 'wrap', marginBottom: '12px', fontFamily: 'system-ui', fontSize: '11px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
            <div style={{ width: '12px', height: '12px', background: '#1a3a6b', borderRadius: '2px' }}/>
            <span style={{ color: 'var(--ink2)' }}>Has audit reports</span>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
            <div style={{ width: '12px', height: '12px', background: '#b8d4e8', borderRadius: '2px' }}/>
            <span style={{ color: 'var(--ink2)' }}>No reports yet</span>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
            <div style={{ width: '12px', height: '12px', background: '#E8E8E8', borderRadius: '2px' }}/>
            <span style={{ color: 'var(--ink2)' }}>Different jurisdiction</span>
          </div>
        </div>
      )}
      {isUnion && (
        <div style={{ fontFamily: 'system-ui', fontSize: '12px', color: 'var(--ink3)', marginBottom: '12px' }}>
          Union audit reports cover central government ministries, departments and PSUs across all of India.
          Click the map to view all Union reports.
        </div>
      )}

      {/* SVG Map */}
      <div style={{ background: '#f8fbff', borderRadius: '10px', border: '1px solid var(--rule)', overflow: 'hidden', position: 'relative' }}>
        <svg
          version="1.1"
          xmlns="http://www.w3.org/2000/svg"
          viewBox="0 0 900 1000"
          xmlSpace="preserve"
          style={{ width: '100%', height: 'auto', display: 'block' }}
          onMouseMove={handleMouseMove}
        >
          <g>
            {Object.entries(ID_TO_ISO).map(([svgId]) => (
              <MapPath
                key={svgId}
                svgId={svgId}
                fill={getFill(svgId)}
                cursor={getCursor(svgId)}
                onClick={() => handleClick(svgId)}
                onMouseEnter={(e) => handleMouseEnter(svgId, NAMES[svgId] || svgId, e)}
                onMouseLeave={handleMouseLeave}
              />
            ))}
          </g>

          {/* Callout boxes — static rounded rects for small states/UTs, not needed for union */}
          {!isUnion && (
            <path
              d="M82.508,161.408v-45.095c0-4.888,3.999-8.887,8.887-8.887h87.744c4.888,0,8.887,3.999,8.887,8.887v45.095c0,4.888-3.999,8.887-8.887,8.887H91.395C86.507,170.295,82.508,166.296,82.508,161.408z M353.988,207.214h67.37c3.193,0,5.805-2.612,5.805-5.805v-24.234c0-3.193-2.612-5.805-5.805-5.805h-67.37c-3.193,0-5.805,2.612-5.805,5.805v24.234C348.183,204.601,350.795,207.214,353.988,207.214z M649.06,276.512h125.462c4.703,0,8.551-3.848,8.551-8.551v-25.984c0-4.703-3.848-8.551-8.551-8.551H649.06c-4.703,0-8.551,3.848-8.551,8.551v25.984C640.508,272.664,644.356,276.512,649.06,276.512z M836.28,381.557h57.974c3.16,0,5.746-2.586,5.746-5.746v-28.431c0-3.16-2.586-5.746-5.746-5.746H836.28c-3.16,0-5.746,2.586-5.746,5.746v28.431C830.534,378.972,833.12,381.557,836.28,381.557z M825.206,443.23h62.069c3.528,0,6.414-2.886,6.414-6.414v-33.313c0-3.528-2.886-6.414-6.414-6.414h-62.069c-3.528,0-6.414,2.886-6.414,6.414v33.313C818.792,440.343,821.678,443.23,825.206,443.23z M791.68,501.066h67.554c3.694,0,6.716-3.022,6.716-6.716v-33.356c0-3.694-3.022-6.716-6.716-6.716H791.68c-3.694,0-6.716,3.022-6.716,6.716v33.356C784.964,498.043,787.986,501.066,791.68,501.066z M675.926,519.656h70.46c3.766,0,6.847-3.081,6.847-6.847v-33.103c0-3.766-3.081-6.847-6.847-6.847h-70.46c-3.766,0-6.847,3.081-6.847,6.847v33.103C669.079,516.575,672.16,519.656,675.926,519.656z M647.574,440.45h60.577c9.67,0,17.583-7.912,17.583-17.583v-12.583c0-2.75-2.25-5-5-5h-73.159c-2.75,0-5,2.25-5,5v25.165C642.574,438.2,644.824,440.45,647.574,440.45z M598.248,857.83h174.815c7.268,0,13.215-5.947,13.215-13.215V798.15c0-7.268-5.947-13.215-13.215-13.215H598.248c-7.268,0-13.215,5.947-13.215,13.215v46.465C585.033,851.883,590.98,857.83,598.248,857.83z M381.918,906.994h65.348c3.929,0,7.143-3.214,7.143-7.143v-39.537c0-3.929-3.215-7.143-7.143-7.143h-65.348c-3.929,0-7.143,3.214-7.143,7.143v39.537C374.775,903.779,377.99,906.994,381.918,906.994z M174.992,958.443h62.527c3.422,0,6.222-2.8,6.222-6.222v-30.928c0-3.422-2.8-6.222-6.222-6.222h-62.527c-3.422,0-6.222,2.8-6.222,6.222v30.928C168.77,955.643,171.57,958.443,174.992,958.443z M16.729,918.311h86.119c4.233,0,7.697-3.463,7.697-7.697V876.99c0-4.233-3.463-7.697-7.697-7.697H16.729c-4.233,0-7.697,3.464-7.697,7.697v33.625C9.033,914.848,12.496,918.311,16.729,918.311z M110.066,773.131h54.584c3.201,0,5.82-2.619,5.82-5.82v-31.329c0-3.201-2.619-5.82-5.82-5.82h-54.584c-3.201,0-5.82,2.619-5.82,5.82v31.329C104.246,770.512,106.865,773.131,110.066,773.131z M17.289,653.328h111.449c6.813,0,12.388-5.574,12.388-12.388v-69.85c0-6.813-5.574-12.388-12.388-12.388H17.289c-6.813,0-12.388,5.574-12.388,12.388v69.85C4.902,647.753,10.476,653.328,17.289,653.328z M532.063,337.887h70.836c3.975,0,7.227-3.252,7.227-7.227v-36.99c0-3.975-3.252-7.227-7.227-7.227h-70.836c-3.975,0-7.227,3.252-7.227,7.227v36.99C524.836,334.635,528.088,337.887,532.063,337.887z"
              fill="#f0f4fa"
              stroke="#9ab0cc"
              strokeWidth="1"
              vectorEffect="non-scaling-stroke"
              style={{ pointerEvents: 'none' }}
            />
          )}

          {/* Text labels — only for non-union maps */}
          {!isUnion && (
            <g style={{ pointerEvents: 'none' }}>
              {ALL_LABELS.map(({ svgId, x, y, lines }) => {
                const mapId = svgId.replace('injsvn_', 'injsmap_')
                const isoId = ID_TO_ISO[mapId]
                const inJur = isoId ? isInJurisdiction(isoId, jurisdiction) : false
                const isHovered = mapId === hoveredId
                const hasReports = isoId ? (reportCounts[isoId] || 0) > 0 : false
                const onDark = inJur && (isHovered || hasReports)
                const fill  = !inJur ? '#bbb' : onDark ? '#ffffff' : '#1a3a6b'
                // White halo behind text so it's readable over any fill colour
                const stroke      = onDark ? 'none' : 'rgba(255,255,255,0.9)'
                const strokeWidth = onDark ? 0 : 3
                return (
                  <text key={svgId}
                    x={x} y={y}
                    fontSize="10"
                    fontFamily="system-ui, sans-serif"
                    fontWeight="700"
                    fill={fill}
                    stroke={stroke}
                    strokeWidth={strokeWidth}
                    paintOrder="stroke"
                    textAnchor="start">
                    {lines.map((line, i) =>
                      typeof line === 'string'
                        ? <tspan key={i} x={x} dy={i === 0 ? 0 : 13}>{line}</tspan>
                        : <tspan key={i} x={x + (line as {t:string;dx:number;dy:number}).dx} dy={(line as {t:string;dx:number;dy:number}).dy === 0 ? 0 : 13}>{(line as {t:string;dx:number;dy:number}).t}</tspan>
                    )}
                  </text>
                )
              })}
            </g>
          )}
        </svg>

        {/* Tooltip */}
        {tooltip && (hoveredName || indiaHovered) && (
          <div style={{
            position: 'absolute',
            left: tooltip.x + 12,
            top: tooltip.y - 12,
            background: '#fff',
            border: '1px solid var(--rule)',
            borderRadius: '6px',
            padding: '6px 10px',
            pointerEvents: 'none',
            boxShadow: '0 4px 12px rgba(0,0,0,.12)',
            zIndex: 10,
            whiteSpace: 'nowrap',
          }}>
            {isUnion ? (
              <>
                <div style={{ fontFamily: 'system-ui', fontSize: '12px', fontWeight: 700, color: 'var(--navy)' }}>
                  India — Union
                </div>
                <div style={{ fontFamily: 'system-ui', fontSize: '11px', color: 'var(--ink3)', marginTop: '2px' }}>
                  {totalUnionReports > 0
                    ? `${totalUnionReports} union audit report${totalUnionReports !== 1 ? 's' : ''} — click to view`
                    : 'Click to view union audit reports'}
                </div>
              </>
            ) : (
              <>
                <div style={{ fontFamily: 'system-ui', fontSize: '12px', fontWeight: 700, color: 'var(--navy)' }}>
                  {hoveredName}
                </div>
                <div style={{ fontFamily: 'system-ui', fontSize: '11px', color: 'var(--ink3)', marginTop: '2px' }}>
                  {hoveredCount > 0
                    ? `${hoveredCount} audit report${hoveredCount !== 1 ? 's' : ''} — click to view`
                    : 'No reports available yet'}
                </div>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  )
}

// ── Individual path component with the actual SVG d= data ─────
// Each region is its own component so React only re-renders the
// path that changed colour, not the whole SVG.
function MapPath({ svgId, fill, cursor, onClick, onMouseEnter, onMouseLeave }: {
  svgId: string; fill: string; cursor: string
  onClick: () => void
  onMouseEnter: (e: React.MouseEvent) => void
  onMouseLeave: () => void
}) {
  const d = PATH_DATA[svgId]
  if (!d) return null
  return (
    <path
      id={svgId}
      d={d}
      fill={fill}
      stroke="#FFFFFF"
      strokeWidth="1"
      vectorEffect="non-scaling-stroke"
      style={{ cursor, transition: 'fill .15s' }}
      onClick={onClick}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
    />
  )
}

// ── ALL LABELS — exact positions from original SVG ──────────────
// x,y = text start point (text-anchor: start, matching original SVG behaviour)
// lines: string = single line, object = tspan with dx/dy offsets
